    System.IO.Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget/packages/mstest.testframework/4.2.2/lib/net8.0/MSTest.TestFramework.dll")
};

var resolver = new PathAssemblyResolver(
    System.IO.Directory.GetFiles(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "*.dll")
    .Concat(paths));

using var mlc = new MetadataLoadContext(resolver);
