        if (m.IsGenericMethod)
            parms = $"<{string.Join(",", m.GetGenericArguments().Select(g => g.Name))}>({parms})";
        else
            parms = $"({parms})";
        var obsStr = obs != null ? $" [OBSOLETE: {obs.ConstructorArguments.FirstOrDefault()}]" : "";
        Console.WriteLine($"{m.Name}{parms}{obsStr}");
    }
}
EOF
