using System.Runtime.InteropServices;

var dllPath = Path.Combine(
    Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
    ".nuget/packages/mstest.testframework/4.2.2/lib/net8.0/MSTest.TestFramework.dll");

var runtimeDir = RuntimeEnvironment.GetRuntimeDirectory();
var runtimeDlls = Directory.GetFiles(runtimeDir, "*.dll");

var resolver = new PathAssemblyResolver(runtimeDlls.Append(dllPath));
using var mlc = new MetadataLoadContext(resolver);
var asm = mlc.LoadFromAssemblyPath(dllPath);
var assertType = asm.GetType("Microsoft.VisualStudio.TestTools.UnitTesting.Assert");

foreach (var m in assertType!.GetMethods(BindingFlags.Public | BindingFlags.Static))
{
    if (m.Name is "AreEqual" or "AreNotEqual" or "AreSame")
    {
        var obs = m.CustomAttributes.FirstOrDefault(a => a.AttributeType.Name == "ObsoleteAttribute");
        var parms = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        string sig;
        if (m.IsGenericMethod)
            sig = $"<{string.Join(",", m.GetGenericArguments().Select(g => g.Name))}>({parms})";
        else
            sig = $"({parms})";
        var obsStr = obs != null ? " [OBSOLETE]" : "";
        Console.WriteLine($"{m.Name}{sig}{obsStr}");
    }
}
EOF

